import os
import boto3
import hashlib
import time
import re
from datetime import datetime
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from selenium.common.exceptions import TimeoutException, WebDriverException
from flask import Flask, request, jsonify
from urllib.parse import urlparse
from PIL import Image
import io
import logging

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-thumbnails')
MAX_FILE_SIZE = 10 * 1024 * 1024
SCREENSHOT_TIMEOUT = 30
THUMBNAIL_WIDTH = 800
THUMBNAIL_HEIGHT = 600

s3_client = boto3.client('s3', region_name=AWS_REGION)

ALLOWED_SCHEMES = ['http', 'https']
BLOCKED_DOMAINS = [
    'localhost',
    '127.0.0.1',
    '0.0.0.0',
    '169.254.169.254',
    '::1',
    'metadata.google.internal'
]

def validate_url(url):
    if not url or not isinstance(url, str):
        return False, "Invalid URL format"
    
    if len(url) > 2048:
        return False, "URL too long"
    
    try:
        parsed = urlparse(url)
        
        if parsed.scheme not in ALLOWED_SCHEMES:
            return False, "Only HTTP and HTTPS protocols are allowed"
        
        if not parsed.netloc:
            return False, "Invalid URL: missing domain"
        
        hostname = parsed.hostname
        if not hostname:
            return False, "Invalid URL: missing hostname"
        
        hostname_lower = hostname.lower()
        for blocked in BLOCKED_DOMAINS:
            if hostname_lower == blocked or hostname_lower.endswith('.' + blocked):
                return False, "Access to this domain is not allowed"
        
        if re.match(r'^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.)', hostname):
            return False, "Private IP addresses are not allowed"
        
        if re.match(r'^(fd[0-9a-f]{2}:|fe80:)', hostname, re.IGNORECASE):
            return False, "Private IPv6 addresses are not allowed"
        
        return True, parsed.geturl()
    
    except Exception as e:
        logger.error(f"URL validation error: {str(e)}")
        return False, "Invalid URL format"

def generate_filename(url):
    url_hash = hashlib.sha256(url.encode()).hexdigest()
    timestamp = int(time.time())
    return f"screenshots/{timestamp}_{url_hash}.png"

def get_chrome_driver():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--disable-software-rasterizer')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-plugins')
    chrome_options.add_argument('--disable-images')
    chrome_options.add_argument('--disable-javascript')
    chrome_options.add_argument('--blink-settings=imagesEnabled=false')
    chrome_options.add_argument('--window-size=1920,1080')
    chrome_options.add_argument('--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36')
    chrome_options.add_argument('--disable-web-security')
    chrome_options.add_argument('--disable-features=VizDisplayCompositor')
    
    chrome_options.add_experimental_option('excludeSwitches', ['enable-logging'])
    chrome_options.add_experimental_option('prefs', {
        'profile.default_content_setting_values': {
            'notifications': 2,
            'media_stream': 2,
            'geolocation': 2
        }
    })
    
    service = Service()
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(SCREENSHOT_TIMEOUT)
    
    return driver

def create_thumbnail(screenshot_data, width=THUMBNAIL_WIDTH, height=THUMBNAIL_HEIGHT):
    try:
        image = Image.open(io.BytesIO(screenshot_data))
        
        image.thumbnail((width, height), Image.Resampling.LANCZOS)
        
        output = io.BytesIO()
        image.save(output, format='PNG', optimize=True)
        output.seek(0)
        
        return output.getvalue()
    except Exception as e:
        logger.error(f"Thumbnail creation error: {str(e)}")
        raise

def take_screenshot(url):
    driver = None
    try:
        driver = get_chrome_driver()
        
        driver.get(url)
        
        time.sleep(2)
        
        screenshot_data = driver.get_screenshot_as_png()
        
        if len(screenshot_data) > MAX_FILE_SIZE:
            raise ValueError("Screenshot size exceeds maximum allowed size")
        
        thumbnail_data = create_thumbnail(screenshot_data)
        
        return thumbnail_data
    
    except TimeoutException:
        logger.error(f"Timeout while loading URL: {url}")
        raise Exception("Page load timeout")
    
    except WebDriverException as e:
        logger.error(f"WebDriver error: {str(e)}")
        raise Exception("Failed to capture screenshot")
    
    except Exception as e:
        logger.error(f"Screenshot error: {str(e)}")
        raise
    
    finally:
        if driver:
            try:
                driver.quit()
            except Exception as e:
                logger.error(f"Error closing driver: {str(e)}")

def upload_to_s3(file_data, filename):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=filename,
            Body=file_data,
            ContentType='image/png',
            ServerSideEncryption='AES256',
            ACL='private'
        )
        
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
        
        return url
    
    except Exception as e:
        logger.error(f"S3 upload error: {str(e)}")
        raise Exception("Failed to upload screenshot to storage")

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

@app.route('/screenshot', methods=['POST'])
def screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        
        is_valid, result = validate_url(url)
        if not is_valid:
            return jsonify({'error': result}), 400
        
        validated_url = result
        
        logger.info(f"Taking screenshot of: {validated_url}")
        
        screenshot_data = take_screenshot(validated_url)
        
        filename = generate_filename(validated_url)
        
        screenshot_url = upload_to_s3(screenshot_data, filename)
        
        return jsonify({
            'success': True,
            'screenshot_url': screenshot_url,
            'filename': filename,
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    
    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return jsonify({'error': str(e)}), 400
    
    except Exception as e:
        logger.error(f"Screenshot service error: {str(e)}")
        return jsonify({'error': 'Failed to generate screenshot'}), 500

@app.route('/screenshot/<path:filename>', methods=['GET'])
def get_screenshot(filename):
    try:
        if not re.match(r'^screenshots/\d+_[a-f0-9]{64}\.png$', filename):
            return jsonify({'error': 'Invalid filename'}), 400
        
        presigned_url = s3_client.generate_presigned_url(
            'get_object',
            Params={
                'Bucket': S3_BUCKET,
                'Key': filename
            },
            ExpiresIn=3600
        )
        
        return jsonify({
            'success': True,
            'url': presigned_url
        }), 200
    
    except Exception as e:
        logger.error(f"Error generating presigned URL: {str(e)}")
        return jsonify({'error': 'Failed to retrieve screenshot'}), 500

@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Endpoint not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)